{
  "name": "Smart PDF to Excel Converter",
  "description": "A high-performance utility that uses Gemini AI to intelligently extract tables and structured data from PDF documents and convert them into downloadable Excel spreadsheets."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ExtractedTable {
  sheetName: string;
  rows: Record<string, any>[];
}

export interface ExtractionResult {
  tables: ExtractedTable[];
}

export enum AppStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  PROCESSING = 'PROCESSING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExtractionResult } from "../types";

export const extractDataFromPdf = async (base64Pdf: string): Promise<ExtractionResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'application/pdf',
            data: base64Pdf,
          },
        },
        {
          text: "Extract all tabular data from this PDF. Identify distinct tables and provide them as a JSON structure. For each table, provide a descriptive 'sheetName' and an array of objects 'rows' where each object represents a row in the table. Ensure you capture all headers accurately. If there are multiple pages with the same table structure, merge them into a single sheet.",
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          tables: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                sheetName: { type: Type.STRING },
                rows: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    description: "A dynamic object where keys are column headers and values are cell content"
                  }
                }
              },
              required: ["sheetName", "rows"]
            }
          }
        },
        required: ["tables"]
      },
    },
  });

  const text = response.text;
  if (!text) {
    throw new Error("No data extracted from the PDF.");
  }

  return JSON.parse(text) as ExtractionResult;
};

import React, { useState, useCallback } from 'react';
import * as XLSX from 'xlsx';
import { FileUp, FileSpreadsheet, CheckCircle2, AlertCircle, Loader2, Download, RefreshCw, ChevronRight } from 'lucide-react';
import { AppStatus, ExtractionResult } from './types';
import { extractDataFromPdf } from './services/geminiService';

const App: React.FC = () => {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [error, setError] = useState<string | null>(null);
  const [result, setResult] = useState<ExtractionResult | null>(null);
  const [fileName, setFileName] = useState<string>('');

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (file.type !== 'application/pdf') {
      setError('Please upload a valid PDF file.');
      setStatus(AppStatus.ERROR);
      return;
    }

    setFileName(file.name);
    setStatus(AppStatus.PROCESSING);
    setError(null);

    try {
      const reader = new FileReader();
      reader.onload = async () => {
        const base64 = (reader.result as string).split(',')[1];
        try {
          const extractedData = await extractDataFromPdf(base64);
          setResult(extractedData);
          setStatus(AppStatus.SUCCESS);
        } catch (err: any) {
          console.error(err);
          setError(err.message || 'Failed to process PDF. Please try again.');
          setStatus(AppStatus.ERROR);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError('Error reading file.');
      setStatus(AppStatus.ERROR);
    }
  };

  const downloadExcel = () => {
    if (!result) return;

    const workbook = XLSX.utils.book_new();

    result.tables.forEach((table) => {
      const worksheet = XLSX.utils.json_to_sheet(table.rows);
      XLSX.utils.book_append_sheet(workbook, worksheet, table.sheetName.substring(0, 31)); // Excel limit
    });

    const outputFileName = fileName.replace(/\.[^/.]+$/, "") + ".xlsx";
    XLSX.writeFile(workbook, outputFileName);
  };

  const reset = () => {
    setStatus(AppStatus.IDLE);
    setResult(null);
    setError(null);
    setFileName('');
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col items-center py-12 px-4 sm:px-6 lg:px-8">
      {/* Header */}
      <div className="max-w-3xl w-full text-center mb-12">
        <div className="inline-flex items-center justify-center p-3 bg-blue-600 rounded-2xl shadow-lg mb-6">
          <FileSpreadsheet className="w-8 h-8 text-white" />
        </div>
        <h1 className="text-4xl font-extrabold text-slate-900 tracking-tight sm:text-5xl mb-4">
          PDF to Excel <span className="text-blue-600">Pro</span>
        </h1>
        <p className="text-lg text-slate-600 max-w-2xl mx-auto leading-relaxed">
          AI-powered data extraction. Simply upload your PDF with tables, and we'll convert them into a perfectly formatted Excel sheet in seconds.
        </p>
      </div>

      {/* Main Action Area */}
      <div className="max-w-2xl w-full">
        <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">

          {/* State: Idle */}
          {status === AppStatus.IDLE && (
            <div className="p-12 text-center">
              <label className="group relative block w-full cursor-pointer">
                <input
                  type="file"
                  className="sr-only"
                  accept=".pdf"
                  onChange={handleFileUpload}
                />
                <div className="flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-2xl p-10 bg-slate-50/50 group-hover:border-blue-400 group-hover:bg-blue-50/30 transition-all duration-300">
                  <div className="p-4 bg-white rounded-full shadow-sm mb-4 group-hover:scale-110 transition-transform">
                    <FileUp className="w-8 h-8 text-blue-600" />
                  </div>
                  <span className="text-xl font-semibold text-slate-900 mb-2">Click to upload PDF</span>
                  <p className="text-sm text-slate-500">Maximum file size: 10MB</p>
                </div>
              </label>

              <div className="mt-8 flex items-center justify-center gap-6 text-slate-400">
                <div className="flex items-center gap-2">
                  <CheckCircle2 className="w-4 h-4 text-green-500" />
                  <span className="text-sm">Table Detection</span>
                </div>
                <div className="flex items-center gap-2">
                  <CheckCircle2 className="w-4 h-4 text-green-500" />
                  <span className="text-sm">High Accuracy</span>
                </div>
                <div className="flex items-center gap-2">
                  <CheckCircle2 className="w-4 h-4 text-green-500" />
                  <span className="text-sm">Multi-page support</span>
                </div>
              </div>
            </div>
          )}

          {/* State: Processing */}
          {status === AppStatus.PROCESSING && (
            <div className="p-12 text-center animate-pulse">
              <Loader2 className="w-12 h-12 text-blue-600 animate-spin mx-auto mb-6" />
              <h3 className="text-xl font-bold text-slate-900 mb-2">Analyzing Document...</h3>
              <p className="text-slate-600 mb-6">Gemini AI is extracting structure and identifying tables in <span className="font-mono text-sm bg-slate-100 px-2 py-1 rounded">{fileName}</span></p>
              <div className="w-full bg-slate-100 rounded-full h-2.5 max-w-xs mx-auto overflow-hidden">
                <div className="bg-blue-600 h-2.5 rounded-full w-2/3 animate-[progress_2s_ease-in-out_infinite]"></div>
              </div>
            </div>
          )}

          {/* State: Success */}
          {status === AppStatus.SUCCESS && result && (
            <div className="p-8">
              <div className="flex items-center justify-between mb-8 pb-6 border-b border-slate-100">
                <div className="flex items-center gap-4">
                  <div className="p-3 bg-green-100 rounded-xl">
                    <CheckCircle2 className="w-6 h-6 text-green-600" />
                  </div>
                  <div>
                    <h3 className="font-bold text-slate-900">Conversion Ready</h3>
                    <p className="text-sm text-slate-500">Extracted {result.tables.length} table(s) from your PDF.</p>
                  </div>
                </div>
                <button 
                  onClick={reset}
                  className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                >
                  <RefreshCw className="w-5 h-5" />
                </button>
              </div>

