                        {idx + 1}
                      </div>
                      <div>
                        <p className="font-medium text-slate-900">{table.sheetName}</p>
                        <p className="text-xs text-slate-500">{table.rows.length} rows detected</p>
                      </div>
                    </div>
                    <ChevronRight className="w-4 h-4 text-slate-300" />
                  </div>
                ))}
              </div>

              <button
                onClick={downloadExcel}
                className="w-full flex items-center justify-center gap-3 bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 px-8 rounded-2xl shadow-lg shadow-blue-200 transition-all transform active:scale-[0.98]"
              >
                <Download className="w-5 h-5" />
                Download Excel Spreadsheet
              </button>
            </div>
          )}

          {/* State: Error */}
          {status === AppStatus.ERROR && (
            <div className="p-12 text-center">
              <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-6">
                <AlertCircle className="w-8 h-8 text-red-600" />
              </div>
              <h3 className="text-xl font-bold text-slate-900 mb-2">Oops! Something went wrong</h3>
              <p className="text-slate-600 mb-8 max-w-sm mx-auto">{error || 'An unexpected error occurred while processing your file.'}</p>
              <button
                onClick={reset}
                className="inline-flex items-center gap-2 bg-slate-900 text-white px-6 py-3 rounded-xl font-semibold hover:bg-slate-800 transition-colors"
              >
                Try Another File
              </button>
            </div>
          )}
        </div>

