               <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
               Zero Config
            </h4>
            <p className="text-sm text-slate-500">No need to manually define columns or headers. Our AI handles it all automatically.</p>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes progress {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(200%); }
        }
      `}</style>
    </div>
  );
};

