import { GoogleGenAI, Type } from "@google/genai";
import { ExtractionResult } from "../types";

export const extractDataFromPdf = async (base64Pdf: string): Promise<ExtractionResult> => {
  // Always use the API key directly from process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: 'application/pdf',
            data: base64Pdf,
          },
        },
        {
          text: "Extract all tabular data from this PDF. For each table found, identify its headers and all rows. Return the data as a JSON object containing an array of 'tables'. Each table should have a 'sheetName', a 'headers' array (strings), and a 'rows' array (each row is an array of strings or numbers corresponding to the headers). Ensure consistent column counts across all rows. Merge tables that split across pages if they share the same structure.",
        },
      ],
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          tables: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                sheetName: { type: Type.STRING },
                headers: {
                  type: Type.ARRAY,
                  items: { type: Type.STRING }
                },
                rows: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                  }
                }
              },
              required: ["sheetName", "headers", "rows"]
            }
          }
        },
        required: ["tables"]
      },
    },
  });

  // Extracting text output from GenerateContentResponse using .text property
  const text = response.text;
  if (!text) {
    throw new Error("No data extracted from the PDF.");
  }

  return JSON.parse(text) as ExtractionResult;
};

